func (f *rootFlags) newClient() (*client.Client, error) {
	cfg, err := config.Load(f.configPath)
	if err != nil {
		return nil, configErr(err)
	}
	if cfg.AccessToken == "" {
		alias := ResolveOrgAlias("")
		if alias == "" {
			alias = f.profileName
		}
		if alias != "" {
			profile, err := GetProfile(alias)
			if err != nil {
				return nil, err
			}
			if profile != nil && profile.TokenRef.Service != "" && profile.TokenRef.Key != "" {
				token, err := authpkg.LoadStoredToken(profile.TokenRef)
				if err != nil {
					return nil, configErr(fmt.Errorf("loading token for org %s: %w", alias, err))
				}
				cfg.AccessToken = token.AccessToken
				cfg.RefreshToken = token.RefreshToken
				cfg.TokenExpiry = token.ExpiresAt
				cfg.SalesforceInstanceUrl = token.InstanceURL
				cfg.AuthSource = "profile:" + alias
				if token.InstanceURL != "" {
					cfg.BaseURL = strings.TrimRight(token.InstanceURL, "/")
				}
				_ = TouchProfile(alias)
			}
		}
	}
	c := client.New(cfg, f.timeout, f.rateLimit)
	c.DryRun = f.dryRun
	c.NoCache = f.noCache
	return c, nil
}

